function compact(value, maxLen = 1200) {
  const v = String(value || '').replace(/\s+/g, ' ').trim();
  return v.length > maxLen ? v.slice(0, maxLen) : v;
}

function normalizeUrl(url) {
  const u = String(url || '').trim();
  if (!u || u === 'undefined' || u === 'null') return null;
  return u;
}

function normalizeAddress(line1, postalCode, cityName) {
  const parts = [line1, postalCode, cityName]
    .map(v => String(v || '').trim())
    .filter(Boolean);
  return parts.length ? parts.join(', ') : null;
}

return {
  json: {
    entity_type: 'place',
    entity_id: $json.id,
    model_name: 'gemini-2.5-flash',
    ai_input: {
      name: compact($json.name, 180),
      description_de: compact($json.description_de, 1400),
      category_id: $json.category_id || null,
      category_name: $json.category_name || null,
      city_id: $json.city_id || null,
      city_name: $json.city_name || null,
      address_line_1: compact($json.address_line_1, 200),
      postal_code: compact($json.postal_code, 20),
      address_compact: normalizeAddress($json.address_line_1, $json.postal_code, $json.city_name),
      latitude: $json.latitude ?? null,
      longitude: $json.longitude ?? null,
      website_url: normalizeUrl($json.website_url),
      phone: compact($json.phone, 80)
    }
  }
};

